    ('candidate-ming-5433-7518-4f86', 0, '絶命詩', NULL, NULL, NULL, '底誰憂，
鳳城頭。
君臣義命乾坤，
狐乾戈風雨秋。
極目空淚，
傷心一身。
知難爭討，
忠肝萬古留！', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00961","source_record_id":"CN-NT-CAT-00569","alias_record_ids":["CN-NT-CAT-00569"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E5%90%B3%E7%94%98%E4%BE%86)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5468-9cf3-7fd4', 0, '絶命詩', NULL, NULL, NULL, '碧血九依聖主，
白頭老忠魂。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00962","source_record_id":"CN-NT-CAT-00571","alias_record_ids":["CN-NT-CAT-00571"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E5%91%A8%E9%B3%B3%E7%BF%94)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5289-7406-9806', 0, '絶命詩', NULL, NULL, NULL, '成仁取義，
孔孟所傳。
文信踐之，
何不然。
既掇巍科，
豈可苟全？
三忠祠內，
愧前賢！', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00963","source_record_id":"CN-NT-CAT-00572","alias_record_ids":["CN-NT-CAT-00572"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E5%8A%89%E7%90%86%E9%A0%86)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9673-826f-8b28', 0, '絶命詩·其一', NULL, '五言絶句', 5, '國運遭陽九，
君王遘難時。
人臣當殉節，
忠孝兩無虧。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00964","source_record_id":"CN-NT-CAT-00574","alias_record_ids":["CN-NT-CAT-00574"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9%C2%B7%E5%85%B6%E4%B8%80_(%E9%99%B3%E8%89%AF%E8%AC%A8)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9673-826f-8b28', 0, '絶命詩·其二', NULL, NULL, NULL, '中天懸日月，
四海所畢照。
倏而陰昏，
日月常道。
仰觀我明明，
薄蝕一時變。
電風自南來，
光復天心見。
大夫百執事，
其誰忘明君？
愧沉久，
床笫淹數旬。
背城孰盡瘁，
巷戰杳無聲。
如何社稷靈，
爾順民形。
載舟亦覆，
古今同一轍。
順民即逆民，
參觀非一日。
蒼蒼不可問，
國亡何存？
誓守不二心，
一死報君恩。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00965","source_record_id":"CN-NT-CAT-00575","alias_record_ids":["CN-NT-CAT-00575"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9%C2%B7%E5%85%B6%E4%BA%8C_(%E9%99%B3%E8%89%AF%E8%AC%A8)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-8a31-76f4', 0, '絶命詩·其一', NULL, '七言絶句', 7, '率土皆臣自聖明，
狂氛何事敢縱橫！
驅馳安得赳桓力，
一斬元兇盡洗兵。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00966","source_record_id":"CN-NT-CAT-00577","alias_record_ids":["CN-NT-CAT-00577"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9%C2%B7%E5%85%B6%E4%B8%80_(%E8%A8%B1%E7%9B%B4)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-8a31-76f4', 0, '絶命詩·其二', NULL, '七言絶句', 7, '貫盈臣罪豈容誅，
屠戮腥聞駭毒痛。
罄竹南山書不盡，
任將寸磔有餘辜。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00967","source_record_id":"CN-NT-CAT-00578","alias_record_ids":["CN-NT-CAT-00578"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9%C2%B7%E5%85%B6%E4%BA%8C_(%E8%A8%B1%E7%9B%B4)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-8a31-76f4', 0, '絶命詩·其三', NULL, '七言絶句', 7, '君國深仇慘古今，
么么逆豎逼相侵。
微軀自恨無兵柄，
殺賊惟殷報主心。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00968","source_record_id":"CN-NT-CAT-00579","alias_record_ids":["CN-NT-CAT-00579"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9%C2%B7%E5%85%B6%E4%B8%89_(%E8%A8%B1%E7%9B%B4)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-8a31-76f4', 0, '絶命詩·其四', NULL, '七言絶句', 7, '在天靈爽念高皇，
開闢當年垂裕長。
願侍吾皇遄謁帝，
祈哀仍使國威揚。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00969","source_record_id":"CN-NT-CAT-00580","alias_record_ids":["CN-NT-CAT-00580"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9%C2%B7%E5%85%B6%E5%9B%9B_(%E8%A8%B1%E7%9B%B4)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-8a31-76f4', 0, '絶命詩·其五', NULL, '七言絶句', 7, '一死酬君見血誠，
滿腔忠憤痛難平。
大仇未復身先殞，
漫化啼鵑灑淚盈。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00970","source_record_id":"CN-NT-CAT-00581","alias_record_ids":["CN-NT-CAT-00581"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9%C2%B7%E5%85%B6%E4%BA%94_(%E8%A8%B1%E7%9B%B4)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-8a31-76f4', 0, '絶命詩·其六', NULL, '七言絶句', 7, '擲筆翻然辭世行，
老親幼子隔幽明。
丹心未雪生前恨，
青簡空留死後聲。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00971","source_record_id":"CN-NT-CAT-00582","alias_record_ids":["CN-NT-CAT-00582"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9%C2%B7%E5%85%B6%E5%85%AD_(%E8%A8%B1%E7%9B%B4)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-674e-90a6-83ef', 0, '絶命詩', NULL, NULL, NULL, '人生自古誰無死，
留取丹心照青。
兒孫百仰芳名。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00972","source_record_id":"CN-NT-CAT-00583","alias_record_ids":["CN-NT-CAT-00583"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E6%9D%8E%E9%82%A6%E8%8F%AF)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-8303-666f-6587', 0, '絶命詩', NULL, '五言律詩', 5, '孤臣空灑淚，
天步遂如斯。
妖蝕三光暗，
心盟九廟知。
翠華迷草露，
淮水漲煙澌。
故國千年恨，
忠魂繞玉墀。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00973","source_record_id":"CN-NT-CAT-00584","alias_record_ids":["CN-NT-CAT-00584"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E8%8C%83%E6%99%AF%E6%96%87)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-8d99-862d-82b3', 0, '絶命詩', NULL, '七言聯句', 7, '誰言信國非男子，
延息移時何所為。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00974","source_record_id":"CN-NT-CAT-00585","alias_record_ids":["CN-NT-CAT-00585"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E8%B6%99%E8%98%AD%E8%8A%B3)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5f35-80af-5802', 0, '絶命詩', NULL, NULL, NULL, '虛名廿載誤塵寰，
晚節空學圃閑。
難賦《歸來》如靖節，
聊歌《正氣》續文山。
君恩未報徒長恨，
臣道無虧在克艱。
千秋青史筆，
衣冠二字莫輕刪。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00975","source_record_id":"CN-NT-CAT-00586","alias_record_ids":["CN-NT-CAT-00586"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E5%BC%B5%E8%82%AF%E5%A0%82)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ec3-6bd3-797a', 0, '小遊仙·其一', NULL, '七言律詩', 7, '大夢誰分醜與妍，
白楊風起總茫然。
瓠緣無用從人剖，
膏為能明苦自煎。
桂折蘭摧誠短景，
蕭敷艾苑豈長年？
歸途不向虛無覓，
朽骨徒為蔓蘋纏。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00976","source_record_id":"CN-NT-CAT-00587","alias_record_ids":["CN-NT-CAT-00587"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B0%8F%E9%81%8A%E4%BB%99%C2%B7%E5%85%B6%E4%B8%80_(%E9%BB%83%E6%AF%93%E7%A5%BA)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ec3-6bd3-797a', 0, '小遊仙·其二', NULL, '七言律詩', 7, '為愁草盛稻苗稀，
日暮徐看荷鍤歸。
何處先生多好好？
此中居士故非非。
肥魚不肯憐蛟瘦，
飽鷃偏能笑鶴饑。
請讀蒙莊齊物論，
橫空白月冷侵衣。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00977","source_record_id":"CN-NT-CAT-00588","alias_record_ids":["CN-NT-CAT-00588"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B0%8F%E9%81%8A%E4%BB%99%C2%B7%E5%85%B6%E4%BA%8C_(%E9%BB%83%E6%AF%93%E7%A5%BA)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ec3-6bd3-797a', 0, '小遊仙·其三', NULL, '七言律詩', 7, '散髮人間汗漫遊，
風吹白日忽西流。
淘沙慣嚇斜飛燕，
孔雀偏逢抵觸牛。
鄉里小兒朝拜相，
江湖暴客夜封侯。
神仙赤舌如飛電，
開口舒光笑不休。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00978","source_record_id":"CN-NT-CAT-00589","alias_record_ids":["CN-NT-CAT-00589"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B0%8F%E9%81%8A%E4%BB%99%C2%B7%E5%85%B6%E4%B8%89_(%E9%BB%83%E6%AF%93%E7%A5%BA)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ec3-6bd3-797a', 0, '小遊仙·其四', NULL, '七言絶句', 7, '腹中書任他人曬，
犢鼻褌從甚處懸？
惟有丹心堅自愛，
忍能鑒破化為圓？', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00979","source_record_id":"CN-NT-CAT-00590","alias_record_ids":["CN-NT-CAT-00590"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B0%8F%E9%81%8A%E4%BB%99%C2%B7%E5%85%B6%E5%9B%9B_(%E9%BB%83%E6%AF%93%E7%A5%BA)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ec3-6bd3-797a', 0, '小遊仙·其五', NULL, '七言律詩', 7, '最無根蒂是人群，
會合真成偶爾文。
沙際驚鷗常泛泛，
風前落葉自紛紛。
掉頭東海隨煙霧，
屈指西灞散雨雲。
況復炎涼堪絶倒，
灞陵愁殺故將軍。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00980","source_record_id":"CN-NT-CAT-00591","alias_record_ids":["CN-NT-CAT-00591"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B0%8F%E9%81%8A%E4%BB%99%C2%B7%E5%85%B6%E4%BA%94_(%E9%BB%83%E6%AF%93%E7%A5%BA)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ec3-6bd3-797a', 0, '小遊仙·其六', NULL, '七言律詩', 7, '百年世事弈棋秤，
冷眼常觀局屢更。
烏喙只堪同患難，
龍顏難與共升平。
遙至自有饑鷹擊，
古路曾無狡兔橫？
為報韓盧並宋鵲，
只今公等固當烹。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00981","source_record_id":"CN-NT-CAT-00592","alias_record_ids":["CN-NT-CAT-00592"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B0%8F%E9%81%8A%E4%BB%99%C2%B7%E5%85%B6%E5%85%AD_(%E9%BB%83%E6%AF%93%E7%A5%BA)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-8607-5146-4eba', 0, '絶命詩', NULL, NULL, NULL, '保髮嚴，
扶明一死生。
孤忠惟自許，
義重此身輕。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00982","source_record_id":"CN-NT-CAT-00594","alias_record_ids":["CN-NT-CAT-00594"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E8%98%87%E5%85%86%E4%BA%BA)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ec3-7aef-4f2f', 0, '絶命詩', NULL, NULL, NULL, '面絶商量，
露金剛王。
刀山是道場。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00983","source_record_id":"CN-NT-CAT-00595","alias_record_ids":["CN-NT-CAT-00595"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E9%BB%83%E7%AB%AF%E4%BC%AF)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-5433-53ef-57fa', 0, '絶命詩', NULL, '五言絶句', 5, '蹇遇逃君臣，
臨危猶保身。
甘心命節義，
恥服北夷人。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00984","source_record_id":"CN-NT-CAT-00596","alias_record_ids":["CN-NT-CAT-00596"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E5%90%B3%E5%8F%AF%E5%9F%BA)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-6587-4e58', 0, '絶命詩', NULL, '七言絶句', 7, '三百年前舊姓文，
一心報國許誰聞。
忠魂今夜歸何處，
明月灘頭吊白雲。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00985","source_record_id":"CN-NT-CAT-00597","alias_record_ids":["CN-NT-CAT-00597"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E6%96%87%E4%B9%98)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-6881-4e8e-6d98', 0, '絶命詩', NULL, '五言絶句', 5, '但如生富貴，
誰識死功名。
到頭成個是，
方見古人情。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00986","source_record_id":"CN-NT-CAT-00598","alias_record_ids":["CN-NT-CAT-00598"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E6%A2%81%E4%BA%8E%E6%B6%98)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-590f-5141-5f5e', 0, '絶命詩', NULL, NULL, NULL, '少受父訓，
長荷國恩。
盡心報國，
矢死忠貞。
南部繼覆，
猶望中興。
中興望杳，
何忍長存。
卓哉吾友，
虞求廣成。
勿齋、純如，
子才、蘊生。
願言從之，
握手九京。
人孰無死，
不泯此心。
修身俟死，
敬勵後人。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00987","source_record_id":"CN-NT-CAT-00599","alias_record_ids":["CN-NT-CAT-00599"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E5%A4%8F%E5%85%81%E5%BD%9E)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-772d-660e-6c38', 0, '絶命詩', NULL, NULL, NULL, '明命其永，
嵩祝何年。
生忝祖父，
死依聖賢。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00988","source_record_id":"CN-NT-CAT-00600","alias_record_ids":["CN-NT-CAT-00600"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E7%9C%AD%E6%98%8E%E6%B0%B8)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-674e-5411-4e2d', 0, '絶命詩', NULL, NULL, NULL, '血化萇宏碧，
相燃死灰。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00989","source_record_id":"CN-NT-CAT-00601","alias_record_ids":["CN-NT-CAT-00601"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%95%E5%91%BD%E8%A9%A9_(%E6%9D%8E%E5%90%91%E4%B8%AD)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '同聲歌', NULL, '五言古詩', 5, '今夕是何夕，
側身奉君子。
明明銀燭花，
綢繆細相視。
羅帳畫芙蓉，
映面芙蓉紫。
繡被橫鴛鴦，
正與鴛鴦似。
仰望牛女星，
迢迢不如此。
感君方寸恩，
報君何所是。
願為白藕絲，
藏君心竅裡。
願為衵衣帶，
抱君雙腋底。
亂發纏君心，
柔膚印君齒。
四時願皆春，
願作新花蕊。
永夜明月光，
團圓願初起。
節候有盈虧，
中懷長不毀。
咿喔雞既鳴，
婉孌未能已。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00990","source_record_id":"CN-NT-CAT-00602","alias_record_ids":["CN-NT-CAT-00602"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%90%8C%E8%81%B2%E6%AD%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '秋月', NULL, '七言律詩', 7, '寂寂晴宵望不窮，
楓林疏見月如弓。
天圍素幕鉤初上，
人在方諸影並空。
金粟香生仙省桂，
玉蘭光瘦御街桐。
從他坫杵敲如碎，
偏照離情是夜中。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00991","source_record_id":"CN-NT-CAT-00604","alias_record_ids":["CN-NT-CAT-00604"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%A7%8B%E6%9C%88_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '上陽白髮人', NULL, '五言絶句', 5, '本自緣殊色，
蒙恩入上陽。
君王不相見，
綠髮已侵霜。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00992","source_record_id":"CN-NT-CAT-00605","alias_record_ids":["CN-NT-CAT-00605"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E4%B8%8A%E9%99%BD%E7%99%BD%E9%AB%AE%E4%BA%BA_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '金銅仙人辭漢歌', NULL, '七言古詩', 7, '軒轅不死傳古銅，
彭咸享壽年無窮。
仙人況是金銅骨，
試令伸手行清空。
揖向茂陵尋孝武，
日落紅睛翁仲苦。
莫遣車前祭馬肝，
猶羨文成終漢土。
冷淚如泉濺盤露，
療渴文君有誰鑄。
待搜黃金釁寶莖，
盤銘好勒長門賦。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00993","source_record_id":"CN-NT-CAT-00606","alias_record_ids":["CN-NT-CAT-00606"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%87%91%E9%8A%85%E4%BB%99%E4%BA%BA%E8%BE%AD%E6%BC%A2%E6%AD%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '春晚', NULL, '五言律詩', 5, '中歲愛春色，
春居無所爲。
讀書花落裏，
待客燕歸時。
午夢爐煙過，
晴雲閣氣知。
新香與浮綠，
寒煖遞相移。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00994","source_record_id":"CN-NT-CAT-00607","alias_record_ids":["CN-NT-CAT-00607"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%98%A5%E6%99%9A_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '劍', NULL, NULL, NULL, '萬人新學敵，
一劍自能任。
寶骨寒偏徹，
霜芒熱更侵。
氣銷血，
淚點壯夫心。
風雨自朝夕，
誰知龍欲吟。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00995","source_record_id":"CN-NT-CAT-00608","alias_record_ids":["CN-NT-CAT-00608"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%8A%8D_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '劉生', NULL, '五言律詩', 5, '劉生稱少俠，
十五事遨遊。
射鳥趙家路，
吹簫秦氏樓。
龍媒花下馬，
狐腋雪中裘。
近佩將軍印，
開筵選徹侯。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00996","source_record_id":"CN-NT-CAT-00609","alias_record_ids":["CN-NT-CAT-00609"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%8A%89%E7%94%9F_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '山家', NULL, '五言律詩', 5, '山家隱鄰舍，
樹底有柴門。
望入竹林遠，
微聞雞狗喧。
晚炊人出汲，
野泊艇孤昏。
此處無漁火，
清溪纔發源。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00997","source_record_id":"CN-NT-CAT-00610","alias_record_ids":["CN-NT-CAT-00610"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B1%B1%E5%AE%B6_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '戲贈', NULL, NULL, NULL, '小語恰相宜，
芳蘭笑一枝。
眷風浸水骨，
秋月冷蛾眉。
臉熱微沾粉，
唇甜帶脂。
可堪垂柳外，
初試別離時。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00998","source_record_id":"CN-NT-CAT-00611","alias_record_ids":["CN-NT-CAT-00611"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%88%B2%E8%B4%88_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '春遊曲', NULL, '五言律詩', 5, '步幛緣花歇，
沉香烘柳枝。
酒深明暈玉，
風細罥遊絲。
蛺蝶夢中煖，
鴛鴦睡起疑。
更堪雲霧散，
新月鬬蛾眉。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-00999","source_record_id":"CN-NT-CAT-00612","alias_record_ids":["CN-NT-CAT-00612"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%98%A5%E9%81%8A%E6%9B%B2_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '登滕王閣', NULL, '五言律詩', 5, '豐城劍雲去，
高閣序猶存。
醫物氣時盡，
文章名日尊。
窓開波浪窄，
江作管絃喧。
帝子籍留此，
憑高易愴魂。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01000","source_record_id":"CN-NT-CAT-00613","alias_record_ids":["CN-NT-CAT-00613"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%99%BB%E6%BB%95%E7%8E%8B%E9%96%A3_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '別蘇州', NULL, '七言律詩', 7, '一束松箋報未齊，
詩筒臨發又兼攜。
舟移紺寺逢僧送，
酒卻紅兒剩鳥啼。
素影自憐鷗泛泛，
單衫頻映草萋萋。
佳期尚待平分去，
十日錢塘路向西。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01001","source_record_id":"CN-NT-CAT-00615","alias_record_ids":["CN-NT-CAT-00615"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%88%A5%E8%98%87%E5%B7%9E_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '古意', NULL, '五言絶句', 5, '用髮織郎衣，
縱橫繫胸腹。
縛不得人心，
千絲那能足？', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01002","source_record_id":"CN-NT-CAT-00616","alias_record_ids":["CN-NT-CAT-00616"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%8F%A4%E6%84%8F_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '古劍行', NULL, '五言絶句', 5, '我有殊方劍，
尋常把贈人。
丈夫空手立，
猶自足謀身。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01003","source_record_id":"CN-NT-CAT-00617","alias_record_ids":["CN-NT-CAT-00617"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%8F%A4%E5%8A%8D%E8%A1%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '飲馬長城窟', NULL, '五言絶句', 5, '飲馬長城窟，
城下多腥血。
戰渴口沫乾，
人銜一片雪。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01004","source_record_id":"CN-NT-CAT-00618","alias_record_ids":["CN-NT-CAT-00618"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%A3%B2%E9%A6%AC%E9%95%B7%E5%9F%8E%E7%AA%9F_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '題畫', NULL, '五言絶句', 5, '英州夢米老，
玉山逢大癡。
堂成當信宿，
爲寫澹煙時。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01005","source_record_id":"CN-NT-CAT-00619","alias_record_ids":["CN-NT-CAT-00619"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%A1%8C%E7%95%AB_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '夜夜曲', NULL, '五言絶句', 5, '出門人見郎，
勿亂垂髫髮。
儂自與郎梳，
照以階前月。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01006","source_record_id":"CN-NT-CAT-00620","alias_record_ids":["CN-NT-CAT-00620"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%A4%9C%E5%A4%9C%E6%9B%B2_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '少年行', NULL, '七言絶句', 7, '年少傳聞十二州，
報人讎盡轉多讎。
經行不用變名姓，
醉臥胡姬賣酒樓。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01007","source_record_id":"CN-NT-CAT-00621","alias_record_ids":["CN-NT-CAT-00621"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B0%91%E5%B9%B4%E8%A1%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '商婦詞', NULL, '七言絶句', 7, '天邊雲湧浪花紅，
日落當門海外峯。
望得遠帆猶不辨，
江魚多趁石猶風。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01008","source_record_id":"CN-NT-CAT-00622","alias_record_ids":["CN-NT-CAT-00622"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%95%86%E5%A9%A6%E8%A9%9E_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '山中', NULL, '七言絶句', 7, '寂寂春眠野夢多，
酒醒那識夜如何。
山中慣不聞雞犬，
只是天明鳥便歌。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01009","source_record_id":"CN-NT-CAT-00623","alias_record_ids":["CN-NT-CAT-00623"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B1%B1%E4%B8%AD_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '湖上', NULL, '七言絶句', 7, '承恩坊裏綠楊煙，
翠幄朱樓大道邊。
誰似儂家湖口住，
當門人上木蘭船。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01010","source_record_id":"CN-NT-CAT-00624","alias_record_ids":["CN-NT-CAT-00624"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%B9%96%E4%B8%8A_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '閨情', NULL, '五言古詩', 5, '明月皎夜光，
朝鏡如懸水。
照影猶自可，
照形歎相似。
夫子抗達節，
迢迢萬餘里。
肯爲兒女拘，
賤妾愁獨爾。
芝蘭不再榮，
舜華胡足恃。
空房挺光豔，
將無鬼神喜。
芳盛乃遐棄，
彫落徒自恥。
嫁夫勿男兒，
娶婦勿女子。
男兒志四方，
女容易衰改。
何以副中情，
比翼棲連理。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01011","source_record_id":"CN-NT-CAT-00626","alias_record_ids":["CN-NT-CAT-00626"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%96%A8%E6%83%85_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '結客少年場行', NULL, '五言古詩', 5, '生兒未齊戶，
結客少年場。
借問結交人，
不數秦舞陽。
泣者高漸離，
深沉者田光。
醉者名灌夫，
美者張子房。
感恩思報仇，
相送大道傍。
白面坐桃花，
匕首光如霜。
，俠骨違故鄉。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01012","source_record_id":"CN-NT-CAT-00627","alias_record_ids":["CN-NT-CAT-00627"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%B5%90%E5%AE%A2%E5%B0%91%E5%B9%B4%E5%A0%B4%E8%A1%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '苦寒行', NULL, '五言古詩', 5, '遠行良自苦，
南人馳北道。
燒冰雜塵飯，
鬻豆作馬草。
火凍夜雪光，
霜籠朝鬢老。
途遠行入夜，
日短起喚早。
路傍多枯樹，
枝重垂欲倒。
路下多危石，
水乾墄如搗。
前有餓虎啼，
後有僵魂槁。
問爾何所爲，
驚惶亂懷抱。
燕姬直酒壚，
趙室橫錦襖。
過耳不留聽，
入目如蔽好。
築金共馳駿，
獻玉慎懷寶。
旅人誡先笑，
懊惱復懊惱。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01013","source_record_id":"CN-NT-CAT-00628","alias_record_ids":["CN-NT-CAT-00628"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%8B%A6%E5%AF%92%E8%A1%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '放歌行', NULL, '五言古詩', 5, '龍肉不可飽，
珠貝不如衣。
放臣恥忠名，
察主容佞詞。
重雲障白日，
蚤暮安能知。
相去日以遠，
誰見君所爲。
行行遵大道，
齪齪如伏機。
蟬緌翼爲重，
范冠毒與懷。
臬音豈療妒，
狐媚生疑猜。
中夜獨延佇，
昂首臨高臺。
占星望恩赦，
懷德視泰階。
豈敢厭溝瀆，
庶幾興草萊。
平沉楚艾滋，
夷養周原開。
聽我放歌行，
千古有同哀。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01014","source_record_id":"CN-NT-CAT-00629","alias_record_ids":["CN-NT-CAT-00629"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%94%BE%E6%AD%8C%E8%A1%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '飲酒', NULL, '五言古詩', 5, '豔女每擅寵，
才人多好名。
不如遠妒忌，
尊酒見平生。
杯勺興斯夕，
濯濯初月晴。
呼吸遍形氣，
澹動開神明。
何以趣我遊，
三復山海經。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01015","source_record_id":"CN-NT-CAT-00630","alias_record_ids":["CN-NT-CAT-00630"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%A3%B2%E9%85%92_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '莫愁曲', NULL, '五言古詩', 5, '茸茸沙樹煙，
沙白高如山。
青山搖水動，
歡去幾時還。
山青有時綠，
搖櫓聲相續。
載夢過江來，
聽我莫愁曲。
身是江南人，
不見江南春。
春風吹裙帶，
拂起落花塵。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01016","source_record_id":"CN-NT-CAT-00631","alias_record_ids":["CN-NT-CAT-00631"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%8E%AB%E6%84%81%E6%9B%B2_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '水碓', NULL, '七言古詩', 7, '瀠流入咽瑠璃吐，
老去姮娥眠玉兔。
村娃閒鬬隔溪砧，
轆轤自攪蟾蜍步。
催卻鮫人頻爲織，
冰窟成衣雲臼食。
寒巖逗雨乍停風，
溜湧舂高曾未息。
吟蟬相杵夜無聲，
山魈寂寂點鼉更。
惟有殘霞搗難碎，
晴光曉曳長天明。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01017","source_record_id":"CN-NT-CAT-00632","alias_record_ids":["CN-NT-CAT-00632"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%B0%B4%E7%A2%93_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '神絃曲', NULL, NULL, 7, '蜃吐三山虹作道，
桑田童女秦年老。
喃喃梵語喚西風，
魂兮不語吹遙空。
雷形雙鳥飛斜雨，
淚眼看之疑曳苧。
弟兄德祖兼文舉，
騎魚瞥作芙蓉主。
社公叩挽哀無力，
浪花張天鹽雪白。
神巫好唱謝家詩，
花外沉沉夢顔色。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01018","source_record_id":"CN-NT-CAT-00633","alias_record_ids":["CN-NT-CAT-00633"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%A5%9E%E7%B5%83%E6%9B%B2_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '青樓曲', NULL, '七言律詩', 7, '寶鏡眉新龍鼻古，
妝成嘿嘿憑箏語。
新晴隔水綠窓開，
璃瓶澡露荼薇雨。
西城粉堞花離離，
一雙蜻蜒銜尾飛。
經年忽憶金釵客，
樓上吹香曬舞衣。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01019","source_record_id":"CN-NT-CAT-00635","alias_record_ids":["CN-NT-CAT-00635"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%9D%92%E6%A8%93%E6%9B%B2_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '竹', NULL, '七言律詩', 7, '窓紗煙紋破遙峯，
粉枝搖落花鬚紅。
參差濃澹天玲瓏，
流泉浸聲寒影中。
美人停梭擲春思，
井闌日午簷陰翠。
歸客瀟湘枕上聽，
茗椀桃笙酣碧醉。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01020","source_record_id":"CN-NT-CAT-00636","alias_record_ids":["CN-NT-CAT-00636"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%AB%B9_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '秋胡詩', NULL, '五言古詩', 5, '良日空氣淑，
新綠光榮敷。
揭筐自尋陌，
婦出堂留姑。
娟娟頗自憐，
艷髮姿有餘。
玄鬟窈窕鉠，
鵠袂徘徊孤。
遂感行路人，
寧知為故夫。
冶慎以內持，
歸來見秋胡。
美目曾盻睞，
賴保芳濯軀。
忸怩采桑間，
男女胡不殊。
懷金亦雲賂，
誰雲非若濡。
未保君子疑，
慚極思各途。
所以堅貞婦，
垢形怕異趨。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01021","source_record_id":"CN-NT-CAT-00637","alias_record_ids":["CN-NT-CAT-00637"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%A7%8B%E8%83%A1%E8%A9%A9_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '七里灘', NULL, NULL, NULL, '長灘激波白，
夏日移陰遲。
疊巘生雲，
鳴鳥飛動枝。
石床苔蘚古，
舟溯環湍歧。
科頭一釣竿，
仰眺留餘思。
方臺有古人，
子陵乃吾師。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01022","source_record_id":"CN-NT-CAT-00638","alias_record_ids":["CN-NT-CAT-00638"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E4%B8%83%E9%87%8C%E7%81%98_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '悲哉行', NULL, NULL, NULL, '江魂夜熱鴊露，
田光俛嘆荊卿怒。
風吹白浪上崑崙，
海水千年騎馬渡。
丈夫鬚眉但如此，
敲徹肝腸不相視。
買絲繡面難繡心，
餐英貫蕊徒枯吟。
黯黯浮雲紅日入，
不如飲酒兼吞泣。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01023","source_record_id":"CN-NT-CAT-00639","alias_record_ids":["CN-NT-CAT-00639"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E6%82%B2%E5%93%89%E8%A1%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '燕歌行', NULL, NULL, NULL, '金釵十二成兩行，
玉顏紅袂環相當。
垂垂膩雲鬢輝煌，
銀燭參差競明光。
逢逄擊鼓齊登堂，
舉鼎烹牛炙肥羊。
主人斜飛琥珀觴，
簾前錯雜風和香。
高歌起舞前為將，
一鬥一石殊未央。
酒酣意氣橫飛揚，
鳴絃激管排雙雙。
交加為壽奉瓊漿，
歌喉變合宮與商，
賤妾聲轉情且長。
十四邯鄲倡，
經過音韻詩繞梁，
門閣次弟隨荒涼。
會須努力各自強，
漏沉為歡入花房。
其如紅日高東方，
願君百歲長如疆。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01024","source_record_id":"CN-NT-CAT-00640","alias_record_ids":["CN-NT-CAT-00640"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%87%95%E6%AD%8C%E8%A1%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '猛虎行', NULL, NULL, NULL, '南山張羅，
北山道阻。
欲東復西，
其如猛虎。
猛虎前致詞，
鋸牙旌其尾。
一日不食人，
肝腸飢欲死。
吁嗟此下人，
豈不聞談嘆其聲，
眈眈其視。
高堂為虎穴，
誰道探其子。
道建騶虞，
曾不相似。
冷戶無餘脂，
白骨無榮髓。
嗟爾虎，
不食人，
人皆食之矣。
奪爾之食，
不如與爾。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01025","source_record_id":"CN-NT-CAT-00641","alias_record_ids":["CN-NT-CAT-00641"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%8C%9B%E8%99%8E%E8%A1%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '善哉行', NULL, NULL, NULL, '人生百年，
晝夜平分。
與我之日，
三萬六千。
日月周天，
上有仙人。
勞勞災咎，
爲束星躔。
厚恩高義，
揮手量錢。
所求不應，
兄弟失歡。
顯名厚寔，
畏盜憂讒。
念爲貧賤，
其如子孫。
大鳥翩翩，
羨乘長風。
會舉兩翼，
安得息肩。
成金點石，
所貴神丹。
慷慨結客，
毋有貳心。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01026","source_record_id":"CN-NT-CAT-00642","alias_record_ids":["CN-NT-CAT-00642"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%96%84%E5%93%89%E8%A1%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '西門行', NULL, NULL, NULL, '出西門，
衣裘輕，
策馬肥。
愚人貪財，
愛惜費思，
舉手代爲散之。
含美酒，
唼西施。
少年馮子都，
吹簫鼓瑟，
隨我驅馳。
人生不行樂，
即不死，
老尚何爲。
即不死，
老尚何爲。
積金欲遺子孫，
子孫愚癡。
子孫賢，
愧畏人嗤。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01027","source_record_id":"CN-NT-CAT-00643","alias_record_ids":["CN-NT-CAT-00643"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E8%A5%BF%E9%96%80%E8%A1%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '將進酒', NULL, NULL, NULL, '糟如丘，
麴作塵。
送花落，
迎花新。
笑君不飲，
何以爲親。
吳兒嬌，
楚臣苦。
醉無憂，
醒無主，
黃鶯自歌蝶自舞。
杯盤出古窰，
未必墳頭土。
朝爲雲，
暮爲雨。
安所得杜康，
變作巫山女。
朝朝莫莫，
不知其數。
蒸香滴酪沉青天，
花間酩酊寧須錢。
富貴自不暇，
貧賤且陶然。
死願作天上星，
生願爲地上仙。
今宵但可浸明月，
倒瀉珍珠那不前。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01028","source_record_id":"CN-NT-CAT-00644","alias_record_ids":["CN-NT-CAT-00644"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%B0%87%E9%80%B2%E9%85%92_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '塞下曲', NULL, '五言絶句', 5, '塵動起秋風，
燈黃夜帳中。
不寐磨長劍，
明朝第一功。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01029","source_record_id":"CN-NT-CAT-00645","alias_record_ids":["CN-NT-CAT-00645"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%A1%9E%E4%B8%8B%E6%9B%B2_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '子夜歌', NULL, '五言絶句', 5, '狂風滅燭光，
房櫳映飛雪。
解衣莫畏寒，
見儂情自熱。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01030","source_record_id":"CN-NT-CAT-00646","alias_record_ids":["CN-NT-CAT-00646"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E5%AD%90%E5%A4%9C%E6%AD%8C_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ece-9042-7403', 0, '采蓮曲', NULL, NULL, NULL, '湖頭采蓮女，
不向藕花前。
笑臉暈芙蓉，
相看采蓮。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01031","source_record_id":"CN-NT-CAT-00647","alias_record_ids":["CN-NT-CAT-00647"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%87%87%E8%93%AE%E6%9B%B2_(%E9%BB%8E%E9%81%82%E7%90%83)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-59da-5947-80e4', 0, '秋夜', NULL, '五言古詩', 5, '遥夜苦無寐，
起視明月光。
涼風天上來，
隨月入我堂。
披衣步前除，
獨立以傍徨。
蟪蛄既已鳴，
鴻雁亦來翔。
感此時物變，
怨彼去日長。
生非金石姿，
安得恒壽康。
憂來不可輟，
慷慨吟此章。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01032","source_record_id":"CN-NT-CAT-00648","alias_record_ids":["CN-NT-CAT-00648"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%A7%8B%E5%A4%9C_(%E5%A7%9A%E5%A5%87%E8%83%A4)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-ming-9ec3-9053-5468', 0, '飛來峰', NULL, '五言律詩', 5, '登岸何所極，
古剎碧松邊。
濤氣歸巉石，
泉心與靜絃。
墜花留過客，
放鳥認前年。
不識青坪路，
今搴百丈蓮。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01033","source_record_id":"CN-NT-CAT-00649","alias_record_ids":["CN-NT-CAT-00649"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E9%A3%9B%E4%BE%86%E5%B3%B0_(%E9%BB%83%E9%81%93%E5%91%A8)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-6b50-967d-7384', 0, '登嶽陽樓', NULL, '七言律詩', 7, '江出夷陵西復西，
東陵城上倚天梯。
月生巫山尋常見，
雪壓君山一字低。
岩客朗吟歸鶴遠，
巴童清夢曉猿啼。
如何偉絶東南觀，
不遣謫仙蘇二題。', 'parsed', 'cnnt-auto', '{"queue_id":"CN-TR-01034","source_record_id":"CN-NT-CAT-00650","alias_record_ids":["CN-NT-CAT-00650"],"batch":"song-yuan-ming-auto","source_url":"https://zh.wikisource.org/wiki/%E7%99%BB%E5%B2%B3%E9%98%B3%E6%A5%BC_(%E6%AC%A7%E9%98%B3%E7%8E%84)","review_status":"auto-extracted","review_reasons":[]}'),
    ('candidate-yuan-738b-5195', 0, '春寒', NULL, '五言律詩', 5, '春寒多雨水，
地僻少輪蹄。
濕氣連山暗，
孤梅近竹低。
林空飢鳥集，
城冷野狐啼。
回首關河道，
