INSERT INTO poems (
  poet_id, poem_no, volume, title_zh, title_ko, category, meter, body_zh,
  is_notable, status, quality, review_memo
)
SELECT
  p.id,
  COALESCE(existing_poem_count.max_poem_no, 0)
    + row_number() OVER (PARTITION BY p.id ORDER BY ip.title_zh, ip.body_zh)::integer,
  ip.volume::integer, ip.title_zh, ip.title_ko, ip.category, ip.meter::integer, ip.body_zh,
  TRUE, ip.status, ip.quality, ip.review_memo
FROM input_poems ip
JOIN poets p ON p.title_id = ip.poet_slug
LEFT JOIN LATERAL (
  SELECT max(poem_no) AS max_poem_no
  FROM poems
  WHERE poet_id = p.id
) existing_poem_count ON TRUE
WHERE NOT EXISTS (
  SELECT 1
  FROM poems existing
  WHERE existing.poet_id = p.id
    AND existing.title_zh = ip.title_zh
    AND existing.body_zh = ip.body_zh
);

UPDATE poets p
SET poem_count = sub.cnt
FROM (
  SELECT poet_id, count(*)::integer AS cnt
  FROM poems
  WHERE poet_id IN (SELECT id FROM poets WHERE title_id IN ('candidate-ming-5433-7518-4f86', 'candidate-ming-5468-9cf3-7fd4', 'candidate-ming-5289-7406-9806', 'candidate-ming-9673-826f-8b28', 'candidate-ming-8a31-76f4', 'candidate-ming-674e-90a6-83ef', 'candidate-ming-8303-666f-6587', 'candidate-ming-8d99-862d-82b3', 'candidate-ming-5f35-80af-5802', 'candidate-ming-9ec3-6bd3-797a', 'candidate-ming-8607-5146-4eba', 'candidate-ming-9ec3-7aef-4f2f', 'candidate-ming-5433-53ef-57fa', 'candidate-ming-6587-4e58', 'candidate-ming-6881-4e8e-6d98', 'candidate-ming-590f-5141-5f5e', 'candidate-ming-772d-660e-6c38', 'candidate-ming-674e-5411-4e2d', 'candidate-ming-9ece-9042-7403', 'candidate-ming-59da-5947-80e4', 'candidate-ming-9ec3-9053-5468', 'candidate-yuan-6b50-967d-7384', 'candidate-yuan-738b-5195', 'candidate-song-8d99-8543', 'candidate-song-6731-71b9', 'candidate-song-65b9-4fe1-5b7a', 'candidate-yuan-7518-6cf3', 'candidate-song-767d-7389-87fe'))
  GROUP BY poet_id
) sub
WHERE p.id = sub.poet_id;

